/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Run a vision-language model on an image and a text prompt.
 * @param {ImagePipelineInputs} images The image(s) to process.
 * @param {string|string[]} texts The text prompt(s) to condition the generation on.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [options] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An object (or array of objects) containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using an `AutoModelForImageTextToText`. This pipeline generates text
 * conditioned on an image and a text prompt.
 *
 * **Example:** Generate text from an image and a text prompt w/ `Xenova/tiny-random-LlavaForConditionalGeneration`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'Xenova/tiny-random-LlavaForConditionalGeneration');
 * const image = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const prompt = 'USER: <image>\nWhat is in this image? ASSISTANT:';
 * const output = await pipe(image, prompt);
 * // [{ generated_text: '...' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, texts, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);
        const preparedTexts = isBatched ? texts : [texts];

        const inputs = await this.processor(preparedImages, preparedTexts, {
            padding: true,
            truncation: true,
        });

        // Decode input tokens to determine prompt character lengths for stripping echoed input
        let promptLengths;
        if (inputs.input_ids && inputs.input_ids.dims.at(-1) > 0) {
            promptLengths = this.tokenizer.batch_decode(inputs.input_ids, {
                skip_special_tokens: true,
            }).map(x => x.length);
        }

        const outputTokenIds = /** @type {Tensor} */(await this.model.generate({
            ...inputs,
            ...generate_kwargs,
        }));

        const decoded = this.tokenizer.batch_decode(outputTokenIds, {
            skip_special_tokens: true,
        });

        /** @type {ImageTextToTextOutput[]} */
        const toReturn = decoded.map((text, i) => [{
            generated_text: promptLengths ? text.slice(promptLengths[i]) : text,
        }]);

        return isBatched ? toReturn : toReturn[0];
    }
}

/**
 * @typedef {Object} ImageClassificationSingle
